+func stripBoolFlag(args []string, name string, out **bool) []string {
+	if name == "" {
+		return args
+	}
+	long := "--" + name
+	short := "-" + name
+	keep := make([]string, 0, len(args))
+	for _, arg := range args {
+		if arg == long || arg == short {
+			val := true
+			*out = &val
+			continue
+		}
+		keep = append(keep, arg)
+	}
+	return keep
+}
